const raw = $env.MONITOR_SERVERS_JSON || '[]';
let servers;
try { servers = JSON.parse(raw); } catch (e) { servers = []; }
return servers.map(s => ({ json: s }));

// State diff: compare current status vs last run, emit alerts for changes only.
const staticData = $getWorkflowStaticData('global');
staticData.lastSeen = staticData.lastSeen || {};
staticData.alerts = staticData.alerts || {};

const alerts = [];   // new alerts to send
const recoveries = [];   // alerts that have cleared
const nowKeys = new Set();

for (const item of $input.all()) {
  const data = item.json;
  const server = data.server || 'unknown';
  const ts = data.timestamp || new Date().toISOString();

  // Container health
  for (const c of (data.containers || [])) {
    const key = <code>${server}::container::${c.name}</code>;
    nowKeys.add(key);
    const bad = c.health === 'unhealthy' || c.state === 'exited' || c.state === 'restarting';
    const wasBad = !!staticData.alerts[key];
    if (bad && !wasBad) {
      alerts.push({server, type: 'container', name: c.name, status: c.status, state: c.state, health: c.health});
      staticData.alerts[key] = {ts, status: c.status};
    } else if (!bad && wasBad) {
      recoveries.push({server, type: 'container', name: c.name, sinceTs: staticData.alerts[key].ts});
      delete staticData.alerts[key];
    }
  }

  // Endpoint health
  for (const e of (data.endpoints || [])) {
    const key = <code>${server}::endpoint::${e.name}</code>;
    nowKeys.add(key);
    const bad = !e.ok;
    const wasBad = !!staticData.alerts[key];
    if (bad && !wasBad) {
      alerts.push({server, type: 'endpoint', name: e.name, url: e.url, status: e.status, error: e.error});
      staticData.alerts[key] = {ts, status: e.status, error: e.error};
    } else if (!bad && wasBad) {
      recoveries.push({server, type: 'endpoint', name: e.name, sinceTs: staticData.alerts[key].ts});
      delete staticData.alerts[key];
    }
  }

  // Database health
  for (const db of (data.databases || [])) {
    const key = <code>${server}::db::${db.name}</code>;
    nowKeys.add(key);
    const bad = !db.ok;
    const wasBad = !!staticData.alerts[key];
    if (bad && !wasBad) {
      alerts.push({server, type: 'database', name: db.name, dbType: db.type, error: db.error});
      staticData.alerts[key] = {ts, error: db.error};
    } else if (!bad && wasBad) {
      recoveries.push({server, type: 'database', name: db.name, sinceTs: staticData.alerts[key].ts});
      delete staticData.alerts[key];
    }
  }

  staticData.lastSeen[server] = ts;
}

// Build Telegram message if there's anything to report
function fmtSince(ts) {
  const t = new Date(ts);
  const mins = Math.round((Date.now() - t.getTime()) / 60000);
  if (mins < 60) return <code>${mins} daq</code>;
  if (mins < 1440) return <code>${Math.floor(mins / 60)} soat</code>;
  return <code>${Math.floor(mins / 1440)} kun</code>;
}

let message = '';
if (alerts.length) {
  message += '🔴 <b>Yangi xatolar</b>\n\n';
  for (const a of alerts) {
    if (a.type === 'container') {
      message += <code>• \</code>${a.server}\<code> — container <b>${a.name}</b> → ${a.health}/${a.state}\n</code>;
    } else if (a.type === 'endpoint') {
      message += <code>• \</code>${a.server}\<code> — endpoint <b>${a.name}</b> → ${a.status || 'TIMEOUT'}${a.error ? ' (' + a.error.slice(0, 80) + ')' : ''}\n</code>;
    } else {
      message += <code>• \</code>${a.server}\<code> — DB <b>${a.name}</b> → ${(a.error || 'down').slice(0, 100)}\n</code>;
    }
  }
}
if (recoveries.length) {
  if (message) message += '\n';
  message += '🟢 <b>Tiklandi</b>\n\n';
  for (const r of recoveries) {
    message += <code>• \</code>${r.server}\<code> — ${r.type} <b>${r.name}</b> (${fmtSince(r.sinceTs)} dan keyin)\n</code>;
  }
}

if (!message) {
  // No alerts to send — return empty so the IF node skips Telegram
  return [];
}

return [{ json: { message, alerts: alerts.length, recoveries: recoveries.length } }];
